mapper.update:
UPDATE emp_post_level SET
    name=#{name}, level=#{level}, salary=#{salary}, status=#{status}
WHERE id=#{id}

mapper.select:
SELECT p.id, p.name, p.level, p.salary, p.sort_code, p.status, IFNULL(ec.employee_count, 0) AS employee_count FROM emp_post_level p LEFT JOIN ( SELECT post_level_id, COUNT(*) AS employee_count FROM emp GROUP BY post_level_id ) ec ON ec.post_level_id = p.id
AND p.name LIKE CONCAT('%', #{name}, '%')
ORDER BY p.sort_code ASC, p.id ASC LIMIT #{start}, #{size}
